  ('locality-8b44517b-moex-00222', 'locality-8b44517b', 'locality-8b44517b-moex-111-3082b5f1', 'sub-locality-8b44517b-04', NULL, 'single_choice', '依實務見解，關於公法上返還請求權，下列敘述何者錯誤？', '["衛生福利部中央健康保險署向簽訂健保合約之醫療院所，請求返還溢領之醫療費用給付時，應 提起一般給付之訴", "人民之土地被徵收時，享有徵收補償之公法上請求權", "臺北市政府社會局撤銷違法授益性行政處分後，得以書面行政處分限期命受益人返還已受領之 給付", "行政主體間之給付關係，應依互相協商機制處理，不適用公法上返還請求權之規定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:32+00:00", "source_pdf_sha1": "604b45da09c0", "answer_pdf_sha1": "a7187c62573c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "306", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "勞工行政"}'::jsonb, NULL),
